import React, { useState } from "react";
import {
  getAuth,
  signInWithEmailAndPassword,
  createUserWithEmailAndPassword,
  GoogleAuthProvider,
  signInWithPopup,
} from "firebase/auth";
import { app } from "./firebase/firebaseConfig";
import { FaLeaf, FaGoogle } from "react-icons/fa";

const auth = getAuth(app);

function App() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isRegister, setIsRegister] = useState(false);
  const [message, setMessage] = useState("");

  const handleAuth = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      if (isRegister) {
        await createUserWithEmailAndPassword(auth, email, password);
        setMessage("✅ Registro exitoso. Puedes iniciar sesión.");
      } else {
        await signInWithEmailAndPassword(auth, email, password);
        setMessage("✅ Sesión iniciada correctamente.");
      }
    } catch (error) {
      // 🔹 Manejo de errores personalizados
      switch (error.code) {
        case "auth/email-already-in-use":
          setMessage("⚠️ El correo ya está registrado. Inicia sesión.");
          break;
        case "auth/invalid-email":
          setMessage("⚠️ El correo ingresado no es válido.");
          break;
        case "auth/weak-password":
          setMessage("⚠️ La contraseña debe tener al menos 6 caracteres.");
          break;
        case "auth/user-not-found":
          setMessage("⚠️ No existe una cuenta con este correo.");
          break;
        case "auth/wrong-password":
          setMessage("⚠️ Contraseña incorrecta.");
          break;
        default:
          setMessage("❌ Ocurrió un error. Intenta nuevamente.");
      }
    }
  };

  const handleGoogleLogin = async () => {
    const provider = new GoogleAuthProvider();
    try {
      await signInWithPopup(auth, provider);
      setMessage("✅ Inicio de sesión con Google exitoso.");
    } catch (error) {
      setMessage("❌ Error al iniciar sesión con Google.");
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-500 to-green-700 flex items-center justify-center px-4">
      <div className="bg-white/10 backdrop-blur-md border border-white/20 rounded-2xl p-8 w-full max-w-md shadow-lg text-center">
        <div className="flex items-center justify-center mb-4">
          <FaLeaf className="text-4xl text-white mr-3" />
          <h1 className="text-3xl font-bold text-white">PlantGuard</h1>
        </div>
        <p className="text-white/80 mb-6">
          {isRegister
            ? "Crea una cuenta para continuar"
            : "Inicia sesión en tu cuenta"}
        </p>

        <form onSubmit={handleAuth} className="space-y-4">
          <input
            type="email"
            placeholder="Correo electrónico"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-green-400"
          />

          <input
            type="password"
            placeholder="Contraseña"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-green-400"
          />

          <button
            type="submit"
            className="w-full py-3 bg-green-600 hover:bg-green-700 text-white rounded-lg font-semibold transition"
          >
            {isRegister ? "Registrarse" : "Iniciar Sesión"}
          </button>
        </form>

        <div className="mt-4">
          <button
            onClick={handleGoogleLogin}
            className="w-full flex items-center justify-center gap-2 py-3 bg-white text-gray-700 rounded-lg shadow hover:bg-gray-100 transition"
          >
            <FaGoogle className="text-red-500" /> Iniciar con Google
          </button>
        </div>

        <p className="mt-4 text-sm text-white/80">
          {isRegister ? "¿Ya tienes cuenta?" : "¿No tienes cuenta?"}{" "}
          <button
            onClick={() => {
              setIsRegister(!isRegister);
              setMessage("");
            }}
            className="underline text-white hover:text-green-200"
          >
            {isRegister ? "Inicia sesión" : "Regístrate"}
          </button>
        </p>

        {message && (
          <p className="mt-4 text-white text-sm bg-black/30 rounded-lg p-2">
            {message}
          </p>
        )}
      </div>
    </div>
  );
}

export default App;
